// src/components/ResourcePanel.js
import React, { useState } from "react";
import { RESOURCES, DISASTER_ZONES } from "../data/mockData";
import "./ResourcePanel.css";

const TYPE_COLOR = { medical: "#EF4444", rescue: "#F59E0B", food: "#10B981", shelter: "#3B82F6" };

const FILTERS = ["all", "deployed", "standby", "in-transit"];
const TYPE_FILTERS = ["all", "medical", "rescue", "food", "shelter"];

function UtilBar({ utilized, capacity, color }) {
  const pct = capacity > 0 ? Math.round((utilized / capacity) * 100) : 0;
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "var(--slate)", marginBottom: 4 }}>
        <span>{utilized.toLocaleString()} / {capacity.toLocaleString()}</span>
        <span style={{ color }}>{pct}%</span>
      </div>
      <div className="progress-bar">
        <div className="progress-fill" style={{ width: `${pct}%`, background: pct > 80 ? "#EF4444" : pct > 60 ? "#F59E0B" : color }} />
      </div>
    </div>
  );
}

export default function ResourcePanel({ tick }) {
  const [statusFilter, setStatusFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");

  const filtered = RESOURCES.filter((r) => {
    const statusOk = statusFilter === "all" || r.status === statusFilter;
    const typeOk   = typeFilter   === "all" || r.type   === typeFilter;
    return statusOk && typeOk;
  });

  const getZoneName = (id) => {
    const z = DISASTER_ZONES.find((z) => z.id === id);
    return z ? z.name.split("—")[0].trim() : "—";
  };

  const totals = {
    deployed:   RESOURCES.filter((r) => r.status === "deployed").length,
    standby:    RESOURCES.filter((r) => r.status === "standby").length,
    inTransit:  RESOURCES.filter((r) => r.status === "in-transit").length,
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>Resource Management</h1>
        <p>Track and manage all disaster response resources across zones</p>
      </div>

      {/* Summary cards */}
      <div className="grid-4" style={{ marginBottom: 20 }}>
        <div className="stat-card blue">
          <div className="stat-label">Total Resources</div>
          <div className="stat-value">{RESOURCES.length}</div>
          <div className="stat-sub">Across all types</div>
        </div>
        <div className="stat-card green">
          <div className="stat-label">Deployed</div>
          <div className="stat-value">{totals.deployed}</div>
          <div className="stat-sub">Currently active in zones</div>
        </div>
        <div className="stat-card amber">
          <div className="stat-label">In Transit</div>
          <div className="stat-value">{totals.inTransit}</div>
          <div className="stat-sub">En route to zones</div>
        </div>
        <div className="stat-card critical">
          <div className="stat-label">Standby</div>
          <div className="stat-value">{totals.standby}</div>
          <div className="stat-sub">Ready for deployment</div>
        </div>
      </div>

      <div className="card">
        {/* Filters */}
        <div className="res-filters">
          <div className="filter-group">
            <span className="filter-label">STATUS</span>
            {FILTERS.map((f) => (
              <button
                key={f}
                className={`filter-btn ${statusFilter === f ? "active" : ""}`}
                onClick={() => setStatusFilter(f)}
              >
                {f === "all" ? "All" : f.replace("-", " ")}
              </button>
            ))}
          </div>
          <div className="filter-group">
            <span className="filter-label">TYPE</span>
            {TYPE_FILTERS.map((f) => (
              <button
                key={f}
                className={`filter-btn ${typeFilter === f ? "active" : ""}`}
                onClick={() => setTypeFilter(f)}
                style={typeFilter === f && f !== "all" ? { borderColor: TYPE_COLOR[f], color: TYPE_COLOR[f] } : {}}
              >
                {f === "all" ? "All" : f}
              </button>
            ))}
          </div>
          <div style={{ marginLeft: "auto", fontSize: 12, color: "var(--slate)" }}>
            Showing {filtered.length} of {RESOURCES.length}
          </div>
        </div>

        {/* Table */}
        <div className="res-table-wrap">
          <table className="data-table">
            <thead>
              <tr>
                <th>Resource</th>
                <th>Type</th>
                <th>Status</th>
                <th>Assigned Zone</th>
                <th>Location</th>
                <th style={{ width: 200 }}>Utilization</th>
                <th>Last Update</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((res) => (
                <tr key={res.id}>
                  <td>
                    <div style={{ fontWeight: 500, color: "var(--white)" }}>{res.name}</div>
                    <div style={{ fontSize: 11, color: "var(--slate-dim)", fontFamily: "var(--font-mono)" }}>{res.id.toUpperCase()}</div>
                  </td>
                  <td>
                    <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                      <div style={{ width: 8, height: 8, borderRadius: "50%", background: TYPE_COLOR[res.type], flexShrink: 0 }} />
                      <span style={{ textTransform: "capitalize" }}>{res.type}</span>
                    </div>
                  </td>
                  <td>
                    <span className={`badge badge-${res.status}`}>{res.status}</span>
                  </td>
                  <td>
                    {res.assignedZone
                      ? <span style={{ fontSize: 12 }}>{getZoneName(res.assignedZone)}</span>
                      : <span style={{ color: "var(--slate-dim)", fontSize: 12 }}>Not assigned</span>
                    }
                  </td>
                  <td style={{ fontSize: 12, color: "var(--slate)" }}>{res.location}</td>
                  <td>
                    <UtilBar
                      utilized={res.utilized}
                      capacity={res.capacity}
                      color={TYPE_COLOR[res.type]}
                    />
                  </td>
                  <td style={{ fontFamily: "var(--font-mono)", fontSize: 11, color: "var(--slate-dim)" }}>
                    {new Date(res.lastUpdate).toUTCString().slice(17, 25)} UTC
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
